    Map<String, Integer> weight_by_node = new HashMap<>();
    for (List<String> edge : weight_by_edge.keySet()) {
        weight_by_node.put(edge.get(1), Integer.MAX_VALUE);
        weight_by_node.put(edge.get(0), Integer.MAX_VALUE);
