        T first = arr.get(0);
        arr.remove(0);
        ArrayList<ArrayList<T>> rest = powerset(arr);
        ArrayList<ArrayList<T>> output = new ArrayList<ArrayList<T>>(100);
        ArrayList<T> to_add = new ArrayList<T>(100);
        to_add.add(first);
        for (ArrayList<T> subset : rest) {
            output.add(to_add);
            output.add(subset);
        }
        return output;
    } else {
        ArrayList<ArrayList<T>> empty_set = new ArrayList<ArrayList<T>>();
        ArrayList<T> empty = new ArrayList<T>();
        empty_set.add(empty);
        return empty_set;
    }
}

