        ArrayList<ArrayList> rest_subsets = powerset(rest);
        ArrayList<ArrayList> output = new ArrayList<ArrayList>(100);
        ArrayList to_add = new ArrayList(100);

        ArrayList<ArrayList> combined_subsets = new ArrayList<ArrayList>();
        for (ArrayList subset : rest_subsets) {
            combined_subsets.add(subset);
        }
        combined_subsets.add(new ArrayList());
        for (ArrayList subset : combined_subsets) {
            ArrayList to_add = new ArrayList(subset.size() + 1);
            to_add.add(first);
